import React, { useState, useEffect, useCallback } from "react";
import { X, Plus, Folder, Edit2, Trash2 } from "lucide-react";
import { useAuth } from "../context/AuthContext";
import { API_URL } from "../config/env";

const CustomCategories = ({ onCategorySelect, selectedCategory, onUpdate }) => {
  const { getAuthHeaders } = useAuth();
  const [categories, setCategories] = useState([]);
  const [showModal, setShowModal] = useState(false);
  const [editingCategory, setEditingCategory] = useState(null);
  const [formData, setFormData] = useState({
    name: "",
    icon: "folder",
    color: "#3b82f6",
  });

  const fetchCategories = useCallback(async () => {
    try {
      const response = await fetch(`${API_URL}/categories`, {
        headers: getAuthHeaders(),
      });
      const data = await response.json();
      setCategories(Array.isArray(data) ? data : []);
    } catch (error) {
      console.error("Lỗi khi tải categories:", error);
    }
  }, [getAuthHeaders]);

  useEffect(() => {
    fetchCategories();
  }, [fetchCategories]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const url = editingCategory
        ? `${API_URL}/categories/${editingCategory._id}`
        : `${API_URL}/categories`;
      const method = editingCategory ? "PUT" : "POST";

      const response = await fetch(url, {
        method,
        headers: getAuthHeaders(),
        body: JSON.stringify(formData),
      });

      if (response.ok) {
        await fetchCategories();
        setShowModal(false);
        setFormData({ name: "", icon: "folder", color: "#3b82f6" });
        setEditingCategory(null);
        if (onUpdate) onUpdate();
      }
    } catch (error) {
      console.error("Lỗi:", error);
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm("Bạn có chắc muốn xóa danh mục này?")) return;

    try {
      await fetch(`${API_URL}/categories/${id}`, {
        method: "DELETE",
        headers: getAuthHeaders(),
      });
      await fetchCategories();
      if (onUpdate) onUpdate();
    } catch (error) {
      console.error("Lỗi:", error);
    }
  };

  const handleEdit = (category) => {
    setEditingCategory(category);
    setFormData({
      name: category.name,
      icon: category.icon,
      color: category.color,
    });
    setShowModal(true);
  };

  return (
    <>
      <div className="space-y-2">
        {categories.map((cat) => (
          <div
            key={cat._id}
            className="group relative"
          >
            <button
              onClick={() => onCategorySelect(cat._id)}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-semibold transition-all ${
                selectedCategory === cat._id
                  ? "bg-blue-500 text-white shadow-lg"
                  : "text-gray-700 dark:text-gray-300 hover:bg-blue-50 dark:hover:bg-blue-900/20 bg-white dark:bg-gray-700"
              }`}
            >
              <Folder size={18} style={{ color: selectedCategory === cat._id ? "#fff" : cat.color }} />
              <span className="flex-1 text-left">{cat.name}</span>
              <div className={`flex gap-1 transition-opacity ${
                selectedCategory === cat._id ? "opacity-100" : "opacity-0 group-hover:opacity-100"
              }`}>
                <button
                  onClick={(e) => {
                    e.stopPropagation();
                    handleEdit(cat);
                  }}
                  className={`p-1.5 rounded-lg transition-colors ${
                    selectedCategory === cat._id
                      ? "hover:bg-white hover:bg-opacity-20"
                      : "hover:bg-blue-100 dark:hover:bg-blue-800"
                  }`}
                  title="Chỉnh sửa"
                >
                  <Edit2 size={14} className={selectedCategory === cat._id ? "text-white" : "text-blue-600 dark:text-blue-400"} />
                </button>
                <button
                  onClick={(e) => {
                    e.stopPropagation();
                    handleDelete(cat._id);
                  }}
                  className={`p-1.5 rounded-lg transition-colors ${
                    selectedCategory === cat._id
                      ? "hover:bg-white hover:bg-opacity-20"
                      : "hover:bg-red-100 dark:hover:bg-red-900/20"
                  }`}
                  title="Xóa"
                >
                  <Trash2 size={14} className={selectedCategory === cat._id ? "text-white" : "text-red-600 dark:text-red-400"} />
                </button>
              </div>
            </button>
          </div>
        ))}
        <button
          onClick={() => {
            setEditingCategory(null);
            setFormData({ name: "", icon: "folder", color: "#3b82f6" });
            setShowModal(true);
          }}
          className="w-full flex items-center gap-3 px-4 py-3 rounded-xl font-semibold text-gray-700 dark:text-gray-300 hover:bg-blue-50 dark:hover:bg-blue-900/20 transition-all border-2 border-dashed border-blue-300 dark:border-blue-600 hover:border-blue-400 dark:hover:border-blue-500"
        >
          <Plus size={18} className="text-blue-500" />
          <span>Tạo danh mục mới</span>
        </button>
      </div>

      {showModal && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center p-4 z-50 backdrop-blur-sm">
          <div className="bg-white dark:bg-gray-800 rounded-3xl shadow-2xl p-8 max-w-md w-full border-2 border-gray-100 dark:border-gray-700">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-2xl font-bold text-gray-800 dark:text-white">
                {editingCategory ? "Chỉnh sửa" : "Tạo"} danh mục
              </h3>
              <button 
                onClick={() => setShowModal(false)}
                className="p-2 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-full transition-colors"
              >
                <X size={24} className="text-gray-600 dark:text-gray-300" />
              </button>
            </div>
            <form onSubmit={handleSubmit} className="space-y-6">
              <div>
                <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2">
                  Tên danh mục
                </label>
                <input
                  type="text"
                  value={formData.name}
                  onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                  required
                  className="w-full px-4 py-3 border-2 border-gray-200 dark:border-gray-600 dark:bg-gray-700 dark:text-white rounded-xl focus:border-blue-500 focus:outline-none transition-colors bg-gray-50"
                  placeholder="Nhập tên danh mục..."
                />
              </div>
              <div>
                <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2">
                  Màu sắc
                </label>
                <div className="flex items-center gap-4">
                  <input
                    type="color"
                    value={formData.color}
                    onChange={(e) => setFormData({ ...formData, color: e.target.value })}
                    className="w-20 h-12 rounded-xl cursor-pointer border-2 border-gray-200 dark:border-gray-600"
                  />
                  <span className="text-sm text-gray-600 dark:text-gray-400 font-mono">
                    {formData.color}
                  </span>
                </div>
              </div>
              <div className="flex gap-3 pt-4">
                <button
                  type="button"
                  onClick={() => setShowModal(false)}
                  className="flex-1 px-4 py-3 bg-gray-200 dark:bg-gray-700 text-gray-700 dark:text-gray-300 rounded-xl font-semibold hover:bg-gray-300 dark:hover:bg-gray-600 transition-colors"
                >
                  Hủy
                </button>
                <button
                  type="submit"
                  className="flex-1 px-4 py-3 bg-gradient-to-r from-blue-500 to-purple-600 text-white rounded-xl font-semibold hover:from-blue-600 hover:to-purple-700 transition-all shadow-lg hover:shadow-xl"
                >
                  {editingCategory ? "Cập nhật" : "Tạo"}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </>
  );
};

export default CustomCategories;
